1	<script lang="ts">
2		import { untrack } from 'svelte';
3		import { gql } from 'graphql-request';
4		import { createClient } from '$lib/gql/client';
5	
6		interface Dependency {
7			issueId: string;
8			dependsOnId: string;
9			type: string;
10			createdAt: string | null;
11			createdBy: string | null;
12		}
13	
14		interface Bead {
15			id: string;
16			title: string;
17			status: string;
18			priority: number;
19			issueType: string;
20			owner: string | null;
21			createdAt: string;
22			createdBy: string | null;
23			updatedAt: string;
24			labels: string[] | null;
25			parent: string | null;
26			description: string | null;
27			acceptance: string | null;
28			notes: string | null;
29			dependencies: Dependency[] | null;
30		}
31	
32		let {
33			bead = null,
34			onSuccess,
35			onCancel
36		}: {
37			bead?: Bead | null;
38			onSuccess: (bead: Bead) => void;
39			onCancel: () => void;
40		} = $props();
41	
42		const isUpdate = $derived(bead != null);
43	
44		let title = $state(untrack(() => bead?.title ?? ''));
45		let status = $state(untrack(() => bead?.status ?? 'open'));
46		let priority = $state(untrack(() => bead?.priority ?? 2));
47		let issueType = $state(untrack(() => bead?.issueType ?? ''));
48		let labelsInput = $state(untrack(() => (bead?.labels ?? []).join(', ')));
49		let parent = $state(untrack(() => bead?.parent ?? ''));
50		let description = $state(untrack(() => bead?.description ?? ''));
51		let acceptance = $state(untrack(() => bead?.acceptance ?? ''));
52		let notes = $state(untrack(() => bead?.notes ?? ''));
53		let submitting = $state(false);
54		let error = $state<string | null>(null);
55	
56		const CREATE_MUTATION = gql`
57			mutation BeadCreate($input: BeadInput!) {
58				beadCreate(input: $input) {
59					id title status priority issueType owner createdAt createdBy updatedAt labels parent description acceptance notes
60					dependencies { issueId dependsOnId type createdAt createdBy }
61				}
62			}
63		`;
64	
65		const UPDATE_MUTATION = gql`
66			mutation BeadUpdate($id: ID!, $input: BeadUpdateInput!) {
67				beadUpdate(id: $id, input: $input) {
68					id title status priority issueType owner createdAt createdBy updatedAt labels parent description acceptance notes
69					dependencies { issueId dependsOnId type createdAt createdBy }
70				}
71			}
72		`;
73	
74		async function handleSubmit(e: SubmitEvent) {
75			e.preventDefault();
76			if (!title.trim()) {
77				error = 'Title is required';
78				return;
79			}
80			submitting = true;
81			error = null;
82	
83			const labels = labelsInput
84				.split(',')
85				.map((l) => l.trim())
86				.filter(Boolean);
87	
88			try {
89				const client = createClient();
90				if (isUpdate && bead) {
91					const result = await client.request<{ beadUpdate: Bead }>(UPDATE_MUTATION, {
92						id: bead.id,
93						input: {
94							title: title || undefined,
95							status: status || undefined,
96							priority: priority,
97							issueType: issueType || undefined,
98							labels: labels.length ? labels : undefined,
99							parent: parent || undefined,
100							description: description || undefined,
101							acceptance: acceptance || undefined,
102							notes: notes || undefined
103						}
104					});
105					onSuccess(result.beadUpdate);
106				} else {
107					const result = await client.request<{ beadCreate: Bead }>(CREATE_MUTATION, {
108						input: {
109							title,
110							status,
111							priority,
112							issueType: issueType || undefined,
113							labels: labels.length ? labels : undefined,
114							parent: parent || undefined,
115							description: description || undefined,
116							acceptance: acceptance || undefined,
117							notes: notes || undefined
118						}
119					});
120					onSuccess(result.beadCreate);
121				}
122			} catch (e) {
123				error = e instanceof Error ? e.message : 'Operation failed';
124			} finally {
125				submitting = false;
126			}
127		}
128	
129		const inputClass =
130			'w-full rounded-none border border-border-line bg-bg-elevated px-3 py-2 text-body-sm text-fg-ink placeholder-fg-muted focus:border-accent-lever focus:outline-none focus:ring-1 focus:ring-accent-lever dark:border-dark-border-line dark:bg-dark-bg-elevated dark:text-dark-fg-ink dark:placeholder-dark-fg-muted dark:focus:border-dark-accent-lever';
131		const labelClass =
132			'mb-1 block font-label-caps text-label-caps uppercase text-fg-muted dark:text-dark-fg-muted';
133	
134		function statusBadgeClass(s: string): string {
135			switch (s) {
136				case 'open':
137					return 'badge-status-open';
138				case 'in-progress':
139					return 'badge-status-in-progress';
140				case 'blocked':
141					return 'badge-status-blocked';
142				case 'closed':
143					return 'badge-status-closed';
144				default:
145					return 'badge-status-neutral';
146			}
147		}
148	</script>
149	
150	<form onsubmit={handleSubmit} class="space-y-4">
151		{#if error}
152			<div
153				class="rounded-none border border-error/30 bg-error/10 px-3 py-2 text-sm text-error dark:border-dark-error/30 dark:bg-dark-error/10 dark:text-dark-error"
154			>
155				{error}
156			</div>
157		{/if}
158	
159		<div>
160			<label for="bead-title" class={labelClass}>Title *</label>
161			<input
162				id="bead-title"
163				type="text"
164				bind:value={title}
165				placeholder="Short summary of the work"
166				class={inputClass}
167				required
168			/>
169		</div>
170	
171		<div class="grid grid-cols-2 gap-3">
172			<div>
173				<label for="bead-status" class={labelClass}>Status</label>
174				<select
175					id="bead-status"
176					bind:value={status}
177					class="{inputClass} {statusBadgeClass(status)}"
178				>
179					<option value="open">open</option>
180					<option value="in-progress">in-progress</option>
181					<option value="blocked">blocked</option>
182					<option value="closed">closed</option>
183				</select>
184			</div>
185			<div>
186				<label for="bead-priority" class={labelClass}>Priority</label>
187				<input
188					id="bead-priority"
189					type="number"
190					bind:value={priority}
191					min="1"
192					max="5"
193					class={inputClass}
194				/>
195			</div>
196		</div>
197	
198		<div class="grid grid-cols-2 gap-3">
199			<div>
200				<label for="bead-type" class={labelClass}>Type</label>
201				<input
202					id="bead-type"
203					type="text"
204					bind:value={issueType}
205					placeholder="task, bug, feature…"
206					class={inputClass}
207				/>
208			</div>
209			<div>
210				<label for="bead-parent" class={labelClass}>Parent</label>
211				<input
212					id="bead-parent"
213					type="text"
214					bind:value={parent}
215					placeholder="Parent bead ID"
216					class={inputClass}
217				/>
218			</div>
219		</div>
220	
221		<div>
222			<label for="bead-labels" class={labelClass}>Labels</label>
223			<input
224				id="bead-labels"
225				type="text"
226				bind:value={labelsInput}
227				placeholder="Comma-separated labels"
228				class={inputClass}
229			/>
230		</div>
231	
232		<div>
233			<label for="bead-description" class={labelClass}>Description</label>
234			<textarea
235				id="bead-description"
236				bind:value={description}
237				rows={4}
238				placeholder="Full description / body text"
239				class="{inputClass} resize-y"
240			></textarea>
241		</div>
242	
243		<div>
244			<label for="bead-acceptance" class={labelClass}>Acceptance Criteria</label>
245			<textarea
246				id="bead-acceptance"
247				bind:value={acceptance}
248				rows={3}
249				placeholder="Acceptance criteria"
250				class="{inputClass} resize-y"
251			></textarea>
252		</div>
253	
254		<div>
255			<label for="bead-notes" class={labelClass}>Notes</label>
256			<textarea
257				id="bead-notes"
258				bind:value={notes}
259				rows={2}
260				placeholder="Freeform notes"
261				class="{inputClass} resize-y"
262			></textarea>
263		</div>
264	
265		<div class="flex justify-end gap-2 pt-2">
266			<button
267				type="button"
268				onclick={onCancel}
269				class="rounded-none border border-border-line px-4 py-2 text-body-sm text-fg-muted hover:bg-bg-canvas dark:border-dark-border-line dark:text-dark-fg-muted dark:hover:bg-dark-bg-canvas"
270			>
271				Cancel
272			</button>
273			<button
274				type="submit"
275				disabled={submitting}
276				class="rounded-none bg-accent-lever px-4 py-2 text-body-sm font-medium text-white hover:bg-accent-lever/90 disabled:cursor-not-allowed disabled:opacity-50 dark:bg-dark-accent-lever dark:hover:bg-dark-accent-lever/90"
277			>
278				{submitting ? 'Saving…' : isUpdate ? 'Save changes' : 'Create bead'}
279			</button>
280		</div>
281	</form>
